// // This module implements a two-to-one multiplexer where the output Y is selected based on the input S. When S is 0, Y outputs B, and when S is 1, Y outputs A.
module top_module(
    A,
    B,
    S,
    Y
);input A;
    input B;
    input S;
    output Y;

    assign Y = (S == 0) ? A : B;

endmodule
